import{c as t,Q as a,j as o,m as n}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"Input Latency Myths & Facts","description":"","frontmatter":{},"headers":[],"relativePath":"Input_Latency_Myths.md","filePath":"Input_Latency_Myths.md"}'),s={name:"Input_Latency_Myths.md"};function i(r,e,l,c,u,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="input-latency-myths-facts" tabindex="-1">Input Latency Myths &amp; Facts <a class="header-anchor" href="#input-latency-myths-facts" aria-label="Permalink to &quot;Input Latency Myths &amp; Facts&quot;">​</a></h1><p>The internet is filled with &quot;zero latency&quot; tweaks that are at best placebos, and at worst, detrimental to system stability. The Windows-Optimisations Framework focuses on <strong>hardware-level truths</strong> rather than registry snake oil.</p><p>Here is a breakdown of the most common myths surrounding input latency.</p><hr><h3 id="myth-1-timer-resolution-must-be-forced-to-0-5ms-for-lowest-lag" tabindex="-1">Myth 1: &quot;Timer Resolution must be forced to 0.5ms for lowest lag.&quot; <a class="header-anchor" href="#myth-1-timer-resolution-must-be-forced-to-0-5ms-for-lowest-lag" aria-label="Permalink to &quot;Myth 1: &quot;Timer Resolution must be forced to 0.5ms for lowest lag.&quot;&quot;">​</a></h3><p><strong>Fact:</strong> Prior to Windows 10 Version 2004, games relied heavily on the global system timer. However, modern Windows (and modern games like Valorant, CS2) use <strong>QPC (QueryPerformanceCounter)</strong> for timing, which operates in the microseconds (sub-millisecond) range natively. Forcing the global system timer to <code>0.5ms</code> via 3rd party apps (like ISLC or TimerResolution) forces the CPU to wake up thousands of times a second needlessly, increasing heat and DPC overhead without actually reducing input lag in modern titles.</p><h3 id="myth-2-disabling-hpet-in-the-bios-gives-you-0ms-latency" tabindex="-1">Myth 2: &quot;Disabling HPET in the BIOS gives you 0ms latency.&quot; <a class="header-anchor" href="#myth-2-disabling-hpet-in-the-bios-gives-you-0ms-latency" aria-label="Permalink to &quot;Myth 2: &quot;Disabling HPET in the BIOS gives you 0ms latency.&quot;&quot;">​</a></h3><p><strong>Fact:</strong> HPET (High Precision Event Timer) is a hardware timer. Windows dynamically chooses the best timing source (usually Invariant TSC on modern CPUs). Forcing HPET off via <code>bcdedit /deletevalue useplatformclock</code> or in the BIOS can actually desync audio and cause micro-stutters in games if Windows was relying on it as a fallback. <strong>Recommendation:</strong> Leave HPET enabled in the BIOS, and DO NOT touch the <code>bcdedit</code> commands. Let Windows manage the timer.</p><h3 id="myth-3-8000hz-polling-rate-mice-are-always-better" tabindex="-1">Myth 3: &quot;8000Hz polling rate mice are always better.&quot; <a class="header-anchor" href="#myth-3-8000hz-polling-rate-mice-are-always-better" aria-label="Permalink to &quot;Myth 3: &quot;8000Hz polling rate mice are always better.&quot;&quot;">​</a></h3><p><strong>Fact:</strong> A mouse polling at 8000Hz sends 8,000 interrupts per second to your CPU. If your CPU is not top-tier (e.g., Ryzen 7 7800X3D, Intel i9 14900K), this massive influx of interrupts will cause <strong>DPC latency spikes</strong>, leading to skipped frames and massive stutters in-game. <strong>Recommendation:</strong> 1000Hz is perfectly stable for 99% of setups. 2000Hz is the safe maximum for modern esports. Only use 4000Hz/8000Hz if you have the CPU headroom and a 240Hz+ monitor.</p><h3 id="myth-4-mouse-acceleration-can-t-be-fully-disabled-in-windows" tabindex="-1">Myth 4: &quot;Mouse Acceleration can&#39;t be fully disabled in Windows.&quot; <a class="header-anchor" href="#myth-4-mouse-acceleration-can-t-be-fully-disabled-in-windows" aria-label="Permalink to &quot;Myth 4: &quot;Mouse Acceleration can&#39;t be fully disabled in Windows.&quot;&quot;">​</a></h3><p><strong>Fact:</strong> Windows &quot;Enhance Pointer Precision&quot; (EPP) is a non-linear velocity curve. Turning it off in the GUI disables it. However, older games (like CS 1.6 or old Source engine games) sometimes forcibly re-enable it via the Win32 API. The registry fix (like the one deployed by our <code>Disable_Mouse_Acceleration.ps1</code>) flattens the fallback curve entirely, guaranteeing 1:1 raw input regardless of what legacy software attempts.</p><h3 id="myth-5-changing-usb-polling-rate-in-the-registry-reduces-latency" tabindex="-1">Myth 5: &quot;Changing USB polling rate in the registry reduces latency.&quot; <a class="header-anchor" href="#myth-5-changing-usb-polling-rate-in-the-registry-reduces-latency" aria-label="Permalink to &quot;Myth 5: &quot;Changing USB polling rate in the registry reduces latency.&quot;&quot;">​</a></h3><p><strong>Fact:</strong> Windows 10/11 ignores legacy registry polling overrides (<code>HIDUSBF</code> filters). The only way to change your mouse&#39;s polling rate is via the manufacturer&#39;s official software/firmware (e.g., Logitech G HUB, Razer Synapse, Wootility).</p><hr><h2 id="what-actually-matters" tabindex="-1">What Actually Matters? <a class="header-anchor" href="#what-actually-matters" aria-label="Permalink to &quot;What Actually Matters?&quot;">​</a></h2><p>If you want real input latency improvements:</p><ol><li>Ensure <strong>Exclusive Fullscreen</strong> is working in your games (bypasses DWM buffering).</li><li>Enable <strong>NVIDIA Reflex</strong> or <strong>AMD Anti-Lag</strong> (reduces render queue depth).</li><li>Disable <strong>USB Selective Suspend</strong> (prevents the USB controller from sleeping).</li><li>Maintain high, stable framerates. (Frame time = Input time).</li></ol>',18)])])}const y=t(s,[["render",i]]);export{m as __pageData,y as default};
